+};
+
+function unescapeMarkdown(value: string): string {
+  return value.replace(/\\\\(.)/g, '$1');
+}
+
+function defaultHeadingDisplay(target: string): string | null {
+  const hashIndex = target.indexOf('#');
+  if (hashIndex === -1) {
+    return null;
+  }
+
+  const page = target.substring(0, hashIndex);
+  const heading = target.substring(hashIndex + 1);
+  if (!heading) {
+    return null;
+  }
+
+  return page ? `${page} > ${heading}` : heading;
+}
+
+function parseMarkdownLink(text: string, start: number): MarkdownLink | null {
+  const image = text[start] === '!';
+  const labelStart = start + (image ? 2 : 1);
+  let index = labelStart;
+  let depth = 1;
+
+  while (index < text.length) {
+    const character = text[index];
+    if (character === '\
') {
+      return null;
+    }
+    if (character === '\\\') {
+      index += 2;
+      continue;
+    }
+    if (character === '[') {
+      depth++;
+    } else if (character === ']') {
+      depth--;
+      if (depth === 0) {
+        break;
+      }
+    }
+    index++;
+  }
+
+  if (depth !== 0 || text[index + 1] !== '(') {
+    return null;
+  }
+
+  const label = unescapeMarkdown(text.substring(labelStart, index));
+  index += 2;
+  let target = '';
+
+  if (/\\s/.test(text[index] ?? '')) {
+    while (/[ \	]/.test(text[index] ?? '')) {
+      index++;
+    }
+    if (text[index] !== '<') {
+      return null;
+    }
+  }
+
+  if (text[index] === '<') {
+    index++;
+    const targetStart = index;
+    while (index < text.length && text[index] !== '>') {
+      if (text[index] === '\
') {
+        return null;
+      }
+      if (text[index] === '\\\') {
+        index += 2;
+      } else {
+        index++;
+      }
+    }
+    if (text[index] !== '>') {
+      return null;
+    }
+    target = text.substring(targetStart, index);
+    index++;
+    while (/[ \	]/.test(text[index] ?? '')) {
+      index++;
+    }
+    if (text[index] !== ')') {
+      return null;
+    }
+  } else {
+    const targetStart = index;
+    let parentheses = 0;
+    while (index < text.length) {
+      const character = text[index];
+      if (character === '\
' || (parentheses === 0 && /[ \	]/.test(character))) {
+        return null;
+      }
+      if (character === '\\\') {
+        index += 2;
+        continue;
+      }
+      if (character === '(') {
+        parentheses++;
+      } else if (character === ')') {
+        if (parentheses === 0) {
+          break;
+        }
+        parentheses--;
+      }
+      index++;
+    }
+    if (text[index] !== ')' || parentheses !== 0) {
+      return null;
+    }
+    target = text.substring(targetStart, index);
+  }
+
+  target = unescapeMarkdown(target);
+  if (target.includes('://')) {
+    return null;
+  }
+
+  return {end: index + 1, image, label, target};
+}
+
+function markdownToWiki(text: string, convertLinks: boolean, convertImages: boolean): string {
+  let result = '';
+  let index = 0;
+
+  while (index < text.length) {
+    const isImage = text[index] === '!' && text[index + 1] === '[';
+    const isLink = text[index] === '[';
+    if (!isImage && !isLink) {
+      result += text[index++];
+      continue;
+    }
+
+    const link = parseMarkdownLink(text, index);
+    if (!link || (link.image ? !convertImages : !convertLinks)) {
+      result += text[index++];
+      continue;
+    }
+
+    if (link.image) {
+      const display = link.label && link.label !== link.target ? `|${link.label}` : '';
+      result += `![[${link.target}${display}]]`;
+    } else {
+      const defaultDisplay = defaultHeadingDisplay(link.target);
+      const display = link.label === link.target || link.label === defaultDisplay ? '' : `|${link.label}`;
+      result += `[[${link.target}${display}]]`;
+    }
+    index = link.end;
+  }
+
+  return result;
+}
+
+function wikiToMarkdown(text: string, convertLinks: boolean, convertImages: boolean): string {
+  return text.replace(/(!)?\\[\\[([^\\]\
]+)\\]\\]/g, (match, embed: string | undefined, contents: string) => {
+    const image = !!embed;
+    if (image ? !convertImages : !convertLinks) {
+      return match;
+    }
+
+    const separator = contents.indexOf('|');
+    const target = separator === -1 ? contents : contents.substring(0, separator);
+    const display = separator === -1 ? undefined : contents.substring(separator + 1);
+    if (!target) {
+      return match;
+    }
+
+    if (image) {
+      const alt = display === undefined || /^\\d+(x\\d+)?$/.test(display) ? target : display;
+      return `![${alt}](${target})`;
+    }
+
+    return `[${display ?? defaultHeadingDisplay(target) ?? target}](${target})`;
+  });
+}
